class Solution:
    def findMinimumOperations(self, s1: str, s2: str, s3: str) -> int:
        # Find the longest common prefix among the three strings
        lcp = ""
        for chars in zip(s1, s2, s3):
            if chars[0] == chars[1] == chars[2]:
                lcp += chars[0]
            else:
                break

        # If no common prefix, return -1
        if not lcp:
            return -1

        # Calculate operations needed to truncate each string to the length of the LCP
        ops = 0
        for s in [s1, s2, s3]:
            ops += len(s) - len(lcp)

        return ops
